import json
import pandas as pd
import re

# Get file path for the full CPC data
file_path = None
for key, value in globals().items():
    if 'query_db' in key and '26' in key:
        file_path = value
        break

with open(file_path, 'r') as f:
    data = json.load(f)

print('Total records:', len(data))

# Process all records
year_pattern = re.compile(r'\b(20\d{2})\b')
records_by_year = {}
total_level5 = 0

for record in data:
    date_str = record.get('publication_date', '')
    year_match = year_pattern.search(date_str)

    if year_match:
        year = int(year_match.group(1))

        cpc_json = record.get('cpc', '[]')
        if cpc_json and cpc_json != '[]':
            try:
                cpc_list = json.loads(cpc_json)
                for cpc in cpc_list:
                    code = cpc.get('code', '')
                    if '/' in code:
                        base, subgroup = code.split('/')
                        if subgroup != '00':
                            if year not in records_by_year:
                                records_by_year[year] = {}
                            records_by_year[year][code] = records_by_year[year].get(code, 0) + 1
                            total_level5 += 1
            except:
                continue

print('Years found:', sorted(records_by_year.keys()))
print('Total level 5 records:', total_level5)

# Get all unique CPC codes
years = sorted(records_by_year.keys())
all_codes = set()
for year_data in records_by_year.values():
    all_codes.update(year_data.keys())

print('Unique level 5 codes:', len(all_codes))

# Calculate EMA and find codes peaking in 2022
smoothing = 0.2
peak_2022_codes = []

for code in all_codes:
    ema = None
    max_ema = -1
    peak_year = None

    for year in years:
        count = records_by_year.get(year, {}).get(code, 0)
        if ema is None:
            ema = count
        else:
            ema = (smoothing * count) + ((1 - smoothing) * ema)

        if ema > max_ema:
            max_ema = ema
            peak_year = year

    if peak_year == 2022:
        peak_2022_codes.append((code, max_ema))

# Sort by EMA
peak_2022_sorted = sorted(peak_2022_codes, key=lambda x: x[1], reverse=True)
final_codes = [code for code, ema in peak_2022_sorted]

print('Codes peaking in 2022:', len(final_codes))

result = {
    'total_level5_codes': len(all_codes),
    'codes_peaking_2022': len(final_codes),
    'cpc_codes_best_year_2022': final_codes
}

print('__RESULT__:')
print(json.dumps(result))

